export class LoginModal extends HTMLElement {
  constructor() {
    super();
    this.attachShadow({ mode: "open" });
  }

  connectedCallback(): void {
    this.render();
  }

  private render(): void {
    if (!this.shadowRoot) return;

    this.shadowRoot.innerHTML = `
      <style>
        :host {
          --modal-bg: white;
          --modal-border: #ddd;
          --input-bg: #f5f5f5;
          --text-color: #333;
          --btn-bg: #007bff;
          --btn-hover: #0056b3;
          --error-color: #dc3545;
        }

        .modal-overlay {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          bottom: 0;
          background: rgba(0, 0, 0, 0.5);
          display: flex;
          align-items: center;
          justify-content: center;
          z-index: 1000;
        }

        .modal {
          background: var(--modal-bg);
          border: 1px solid var(--modal-border);
          border-radius: 0.5rem;
          box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
          padding: 2rem;
          width: 100%;
          max-width: 400px;
        }

        h2 {
          margin-top: 0;
          color: var(--text-color);
          text-align: center;
        }

        .form-group {
          margin-bottom: 1rem;
        }

        label {
          display: block;
          margin-bottom: 0.5rem;
          color: var(--text-color);
          font-weight: 500;
        }

        input {
          width: 100%;
          padding: 0.75rem;
          border: 1px solid var(--modal-border);
          border-radius: 0.25rem;
          background: var(--input-bg);
          color: var(--text-color);
          font-size: 1rem;
          box-sizing: border-box;
        }

        input:focus {
          outline: none;
          border-color: var(--btn-bg);
          background: white;
        }

        button {
          width: 100%;
          padding: 0.75rem;
          background: var(--btn-bg);
          color: white;
          border: none;
          border-radius: 0.25rem;
          font-size: 1rem;
          cursor: pointer;
          margin-top: 1rem;
        }

        button:hover {
          background: var(--btn-hover);
        }

        button:disabled {
          opacity: 0.6;
          cursor: not-allowed;
        }

        .error {
          background: #fee;
          color: var(--error-color);
          padding: 0.75rem;
          border-radius: 0.25rem;
          margin-bottom: 1rem;
          border: 1px solid var(--error-color);
        }

        .error-close {
          float: right;
          cursor: pointer;
          font-weight: bold;
        }
      </style>

      <div class="modal-overlay">
        <div class="modal">
          <h2>Login</h2>
          <div id="error-container"></div>
          <form id="login-form">
            <div class="form-group">
              <label for="username">Username</label>
              <input
                type="text"
                id="username"
                name="username"
                placeholder="Enter your username"
                required
                autocomplete="off"
              />
            </div>
            <button type="submit">Login</button>
          </form>
        </div>
      </div>
    `;

    const form = this.shadowRoot.querySelector("#login-form") as HTMLFormElement;
    const usernameInput = this.shadowRoot.querySelector("#username") as HTMLInputElement;

    form.addEventListener("submit", async (e) => {
      e.preventDefault();
      await this.handleLogin(usernameInput.value);
    });

    usernameInput.focus();
  }

  private async handleLogin(username: string): Promise<void> {
    if (!username.trim()) {
      this.showError("Username cannot be empty");
      return;
    }

    const button = this.shadowRoot?.querySelector("button") as HTMLButtonElement;
    if (button) button.disabled = true;

    try {
      const token = await api.login(username);
      store.setState({
        currentUser: username,
        token: token,
        error: null,
      });
    } catch (error) {
      const errorMsg = error instanceof Error ? error.message : String(error);
      this.showError(`Login failed: ${errorMsg}`);
    } finally {
      if (button) button.disabled = false;
    }
  }

  private showError(message: string): void {
    const errorContainer = this.shadowRoot?.querySelector("#error-container");
    if (!errorContainer) return;

    errorContainer.innerHTML = `
      <div class="error">
        <span class="error-close">×</span>
        ${this.escapeHtml(message)}
      </div>
    `;

    const closeBtn = errorContainer.querySelector(".error-close");
    if (closeBtn) {
      closeBtn.addEventListener("click", () => {
        errorContainer.innerHTML = "";
      });
    }
  }

  private escapeHtml(text: string): string {
    const div = document.createElement("div");
    div.textContent = text;
    return div.innerHTML;
  }
}

customElements.define("m3-login-modal", LoginModal);

import { store } from "../store";
import * as api from "../api";

export class Sidebar extends HTMLElement {
  private unsubscribe: (() => void) | null = null;
  private showWorkspaceModal = false;
  private showChannelModal = false;

  constructor() {
    super();
    this.attachShadow({ mode: "open" });
  }

  connectedCallback(): void {
    this.render();
    this.unsubscribe = store.subscribe(() => this.render());
  }

  disconnectedCallback(): void {
    if (this.unsubscribe) {
      this.unsubscribe();
    }
  }

  private render(): void {
    const state = store.getState();
    if (!this.shadowRoot) return;

    this.shadowRoot.innerHTML = `
      <style>
        :host {
          display: flex;
          flex-direction: column;
          width: 250px;
          background: #ecf0f1;
          border-right: 1px solid #bdc3c7;
          overflow-y: auto;
        }

        .sidebar-section {
          padding: 1rem;
          border-bottom: 1px solid #bdc3c7;
        }

        .section-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 0.75rem;
        }

        .section-header h3 {
          margin: 0;
          font-size: 0.875rem;
          text-transform: uppercase;
          color: #34495e;
          letter-spacing: 0.05em;
        }

        .section-btn {
          background: #3498db;
          color: white;
