        }

        .section-btn:hover {
          background: #2980b9;
        }

        .item-list {
          list-style: none;
          padding: 0;
          margin: 0;
        }

        .item {
          padding: 0.5rem;
          margin-bottom: 0.25rem;
          background: white;
          border: 1px solid #bdc3c7;
          border-radius: 0.25rem;
          cursor: pointer;
          display: flex;
          justify-content: space-between;
          align-items: center;
          transition: background 0.2s;
        }

        .item:hover {
          background: #d5dbdb;
        }

        .item.active {
          background: #3498db;
          color: white;
          border-color: #2980b9;
        }

        .item-name {
          flex: 1;
          overflow: hidden;
          text-overflow: ellipsis;
          white-space: nowrap;
        }

        .item-actions {
          display: flex;
          gap: 0.25rem;
          margin-left: 0.5rem;
        }

        .delete-btn {
          background: #e74c3c;
          color: white;
          border: none;
          padding: 0.25rem 0.5rem;
          border-radius: 0.2rem;
          cursor: pointer;
          font-size: 0.75rem;
        }

        .delete-btn:hover {
          background: #c0392b;
        }

        .modal-overlay {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          bottom: 0;
          background: rgba(0, 0, 0, 0.5);
          display: flex;
          align-items: center;
          justify-content: center;
          z-index: 999;
        }

        .modal {
          background: white;
          border-radius: 0.5rem;
          padding: 1.5rem;
          max-width: 400px;
          box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
        }

        .modal h3 {
          margin-top: 0;
          margin-bottom: 1rem;
        }

        .form-group {
          margin-bottom: 1rem;
        }

        .form-group label {
          display: block;
          margin-bottom: 0.5rem;
          font-weight: 500;
        }

        .form-group input {
          width: 100%;
          padding: 0.5rem;
          border: 1px solid #bdc3c7;
          border-radius: 0.25rem;
          box-sizing: border-box;
        }

        .modal-buttons {
          display: flex;
          gap: 0.5rem;
          justify-content: flex-end;
        }

        .modal-btn {
          padding: 0.5rem 1rem;
          border: none;
          border-radius: 0.25rem;
          cursor: pointer;
        }

        .modal-btn-primary {
          background: #3498db;
          color: white;
        }

        .modal-btn-primary:hover {
          background: #2980b9;
        }

        .modal-btn-cancel {
          background: #95a5a6;
          color: white;
        }

        .modal-btn-cancel:hover {
          background: #7f8c8d;
        }

        .error-msg {
          background: #fee;
          color: #c0392b;
          padding: 0.5rem;
          border-radius: 0.25rem;
          margin-bottom: 1rem;
          font-size: 0.875rem;
        }

        .empty-state {
          padding: 1rem;
          text-align: center;
          color: #7f8c8d;
          font-size: 0.875rem;
        }

        .refresh-btn {
          background: #27ae60;
          color: white;
          border: none;
          padding: 0.25rem 0.5rem;
          border-radius: 0.2rem;
          cursor: pointer;
          font-size: 0.75rem;
          margin-left: 0.5rem;
        }

        .refresh-btn:hover {
          background: #229954;
        }
      </style>

      <div class="sidebar-section">
        <div class="section-header">
          <h3>Workspaces</h3>
          <button class="section-btn" id="new-workspace-btn">+ New</button>
          <button class="refresh-btn" id="refresh-workspaces-btn" title="Refresh workspaces">↻</button>
        </div>
        ${
          state.workspaces.length === 0
            ? '<div class="empty-state">No workspaces</div>'
            : `
          <ul class="item-list">
            ${state.workspaces
              .map(
                (ws) => `
              <li class="item ${state.currentWorkspace === ws.name ? "active" : ""}" data-workspace="${this.escapeHtml(ws.name)}">
                <span class="item-name">${this.escapeHtml(ws.name)}</span>
                <div class="item-actions">
                  <button class="delete-btn" data-action="delete-workspace">Delete</button>
                </div>
              </li>
            `
              )
              .join("")}
          </ul>
        `
        }
      </div>

      ${
        state.currentWorkspace
          ? `
        <div class="sidebar-section">
          <div class="section-header">
            <h3>${this.escapeHtml(state.currentWorkspace)}</h3>
          </div>
          <div class="section-header" style="margin-bottom: 0.75rem;">
            <button class="section-btn" id="new-channel-btn" style="flex: 1;">+ New Channel</button>
            <button class="refresh-btn" id="refresh-channels-btn" title="Refresh channels">↻</button>
          </div>
          ${
            state.channels.length === 0
              ? '<div class="empty-state">No channels</div>'
              : `
            <ul class="item-list">
              ${state.channels
                .map(
                  (ch) => `
                <li class="item ${state.currentChannel === ch.name ? "active" : ""}" data-channel="${this.escapeHtml(ch.name)}">
                  <span class="item-name"># ${this.escapeHtml(ch.name)}</span>
                  <div class="item-actions">
                    <button class="delete-btn" data-action="delete-channel">Delete</button>
                  </div>
                </li>
              `
                )
                .join("")}
