          `
          }
        </div>
      `
          : ""
      }
    `;

    this.setupEventListeners(state);
  }

  private setupEventListeners(state: any): void {
    const newWorkspaceBtn = this.shadowRoot?.querySelector("#new-workspace-btn");
    const refreshWorkspacesBtn = this.shadowRoot?.querySelector("#refresh-workspaces-btn");
    const newChannelBtn = this.shadowRoot?.querySelector("#new-channel-btn");
    const refreshChannelsBtn = this.shadowRoot?.querySelector("#refresh-channels-btn");

    newWorkspaceBtn?.addEventListener("click", () => this.showCreateWorkspaceDialog());
    refreshWorkspacesBtn?.addEventListener("click", () => this.loadWorkspaces(state.token));
    newChannelBtn?.addEventListener("click", () => this.showCreateChannelDialog());
    refreshChannelsBtn?.addEventListener("click", () => this.loadChannels(state.token, state.currentWorkspace));

    // Workspace items
    this.shadowRoot?.querySelectorAll(".item[data-workspace]").forEach((item) => {
      item.addEventListener("click", (e) => {
        const target = e.target as HTMLElement;
        if (target.getAttribute("data-action") === "delete-workspace") {
          const wsName = (item as HTMLElement).getAttribute("data-workspace");
          if (wsName) this.deleteWorkspace(state.token, wsName);
        } else {
          const wsName = (item as HTMLElement).getAttribute("data-workspace");
          if (wsName) this.openWorkspace(state.token, wsName);
        }
      });
    });

    // Channel items
    this.shadowRoot?.querySelectorAll(".item[data-channel]").forEach((item) => {
      item.addEventListener("click", (e) => {
        const target = e.target as HTMLElement;
        if (target.getAttribute("data-action") === "delete-channel") {
          const chName = (item as HTMLElement).getAttribute("data-channel");
          if (chName) this.deleteChannel(state.token, state.currentWorkspace, chName);
        } else {
          const chName = (item as HTMLElement).getAttribute("data-channel");
          if (chName) this.openChannel(chName);
        }
      });
    });
  }

  private async loadWorkspaces(token: string | null): Promise<void> {
    if (!token) return;
    try {
      const workspaces = await api.listWorkspaces(token);
      store.setState({
        workspaces: workspaces.map((ws) => ({ name: ws.name, ...ws.data })),
        error: null,
      });
    } catch (error) {
      store.setState({
        error: `Failed to load workspaces: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  private async loadChannels(token: string | null, workspace: string | null): Promise<void> {
    if (!token || !workspace) return;
    try {
      const channels = await api.listChannels(workspace, token);
      store.setState({
        channels: channels.map((ch) => ({ name: ch.name, ...ch.data })),
        error: null,
      });
    } catch (error) {
      store.setState({
        error: `Failed to load channels: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  private showCreateWorkspaceDialog(): void {
    const name = prompt("Enter workspace name:");
    if (name) {
      this.createWorkspace(name);
    }
  }

  private async createWorkspace(name: string): Promise<void> {
    const state = store.getState();
    if (!state.token) return;

    try {
      await api.createWorkspace(name, state.token);
      await this.loadWorkspaces(state.token);
    } catch (error) {
      const errorMsg = error instanceof Error ? error.message : String(error);
      store.setState({
        error: `Failed to create workspace: ${errorMsg}`,
      });
    }
  }

  private async openWorkspace(token: string | null, name: string): Promise<void> {
    if (!token) return;
    store.setState({
      currentWorkspace: name,
      currentChannel: null,
      channels: [],
      posts: [],
    });
    await this.loadChannels(token, name);
  }

  private async deleteWorkspace(token: string | null, name: string): Promise<void> {
    if (!token) return;
    if (!confirm(`Delete workspace "${name}"?`)) return;

    try {
      await api.deleteWorkspace(name, token);
      const state = store.getState();
      await this.loadWorkspaces(token);

      if (state.currentWorkspace === name) {
        store.setState({
          currentWorkspace: null,
          currentChannel: null,
          channels: [],
          posts: [],
        });
      }
    } catch (error) {
      store.setState({
        error: `Failed to delete workspace: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  private showCreateChannelDialog(): void {
    const name = prompt("Enter channel name:");
    if (name) {
      this.createChannel(name);
    }
  }

  private async createChannel(name: string): Promise<void> {
    const state = store.getState();
    if (!state.token || !state.currentWorkspace) return;

    try {
      await api.createChannel(state.currentWorkspace, name, state.token);
      await this.loadChannels(state.token, state.currentWorkspace);
    } catch (error) {
      const errorMsg = error instanceof Error ? error.message : String(error);
      store.setState({
        error: `Failed to create channel: ${errorMsg}`,
      });
    }
  }

  private openChannel(name: string): void {
    store.setState({
      currentChannel: name,
      posts: [],
    });

    const state = store.getState();
    this.loadPosts();
  }

  private async deleteChannel(token: string | null, workspace: string | null, name: string): Promise<void> {
    if (!token || !workspace) return;
    if (!confirm(`Delete channel "${name}"?`)) return;

    try {
      await api.deleteChannel(workspace, name, token);
      const state = store.getState();
      await this.loadChannels(token, workspace);

      if (state.currentChannel === name) {
        store.setState({
          currentChannel: null,
          posts: [],
        });
      }
    } catch (error) {
      store.setState({
        error: `Failed to delete channel: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  private async loadPosts(): Promise<void> {
    const state = store.getState();
    if (!state.token || !state.currentWorkspace || !state.currentChannel) return;

    try {
      const posts = await api.listPosts(state.currentWorkspace, state.currentChannel, state.token);
      store.setState({
        posts: posts.map((post) => ({
          msg: post.data.msg,
          parent: post.data.parent,
          reactions: post.data.reactions,
          extensions: post.data.extensions,
          metadata: {
            name: post.name,
            author: post.author,
            created: post.created,
          },
        })),
        error: null,
      });
    } catch (error) {
      store.setState({
        error: `Failed to load posts: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  private escapeHtml(text: string): string {
    const div = document.createElement("div");
    div.textContent = text;
    return div.innerHTML;
  }
}

