          border-radius: 0.25rem;
          cursor: pointer;
          font-size: 1rem;
        }

        .post-btn:hover {
          background: #2980b9;
        }

        .post-btn:disabled {
          opacity: 0.6;
          cursor: not-allowed;
        }

        .close-reply-btn {
          flex: 1;
          padding: 0.75rem;
          background: #95a5a6;
          color: white;
          border: none;
          border-radius: 0.25rem;
          cursor: pointer;
          font-size: 1rem;
        }

        .close-reply-btn:hover {
          background: #7f8c8d;
        }

        .emoji-picker {
          display: grid;
          grid-template-columns: repeat(4, 1fr);
          gap: 0.5rem;
          padding: 0.5rem;
          background: #ecf0f1;
          border: 1px solid #bdc3c7;
          border-radius: 0.25rem;
          margin-top: 0.5rem;
        }

        .emoji-btn {
          padding: 0.5rem;
          background: white;
          border: 1px solid #bdc3c7;
          border-radius: 0.2rem;
          cursor: pointer;
          font-size: 1rem;
        }

        .emoji-btn:hover {
          background: #d5dbdb;
        }
      </style>

      <div class="chat-header">
        <h2>${state.currentChannel ? "# " + this.escapeHtml(state.currentChannel) : "Select a channel"}</h2>
      </div>

      <div class="messages-container">
        ${
          !state.currentChannel
            ? '<div class="empty-state">No channel selected</div>'
            : state.posts.length === 0
              ? '<div class="empty-state">No messages yet</div>'
              : `
          ${this.renderPosts(state.posts)}
        `
        }
      </div>

      ${
        state.currentChannel
          ? `
        <div class="input-area">
          <div id="reply-label" class="input-label" style="display: none;"></div>
          <div class="input-toolbar">
            <button class="toolbar-btn" id="bold-btn" title="Bold">Bold</button>
            <button class="toolbar-btn" id="italic-btn" title="Italic">Italic</button>
            <button class="toolbar-btn" id="link-btn" title="Link">Link</button>
            <button class="toolbar-btn" id="emoji-btn" title="Reactions">😊</button>
          </div>
          <div id="emoji-picker-container"></div>
          <textarea id="post-input" placeholder="Type a message..."></textarea>
          <div class="post-button-group">
            <button class="post-btn" id="post-btn">Post</button>
            <button class="close-reply-btn" id="close-reply-btn" style="display: none;">Close Reply</button>
          </div>
        </div>
      `
          : ""
      }
    `;

    if (state.currentChannel) {
      this.setupEventListeners();
      this.subscribeToChannel();
    }
  }

  private renderPosts(posts: any[]): string {
    const threaded = this.buildPostTree(posts);
    return threaded.map((post) => this.renderPostWithReplies(post, 0)).join("");
  }

  private buildPostTree(posts: any[]): any[] {
    const postMap = new Map<string, any>();
    const roots: any[] = [];

    // Create map of all posts by name
    posts.forEach((post) => {
      postMap.set(post.metadata.name, { ...post, children: [] });
    });

    // Organize into tree
    postMap.forEach((post) => {
      const parent = post.parent ? postMap.get(post.parent) : null;
      if (parent) {
        parent.children.push(post);
      } else {
        roots.push(post);
      }
    });

    // Sort by creation time
    const sortByTime = (a: any, b: any) => a.metadata.created - b.metadata.created;
    roots.sort(sortByTime);
    roots.forEach((post) => this.sortChildrenRecursive(post, sortByTime));

    return roots;
  }

  private sortChildrenRecursive(post: any, sortFn: any): void {
    post.children.sort(sortFn);
    post.children.forEach((child: any) => this.sortChildrenRecursive(child, sortFn));
  }

  private renderPostWithReplies(post: any, level: number): string {
    const html = this.renderSinglePost(post, level);
    const childrenHtml = post.children.map((child: any) => this.renderPostWithReplies(child, level + 1)).join("");
    return html + childrenHtml;
  }

  private renderSinglePost(post: any, level: number): string {
    const time = new Date(post.metadata.created).toLocaleString();
    const author = post.metadata.author;
    const content = this.formatPostContent(post.msg);

    const reactionsHtml = this.renderReactions(post);

    return `
      <div class="post reply-level-${Math.min(level, 4)}" data-post="${this.escapeHtml(post.metadata.name)}">
        <div class="post-header">
          <span class="post-author">${this.escapeHtml(author)}</span>
          <span class="post-time">${this.escapeHtml(time)}</span>
        </div>
        <div class="post-content">${content}</div>
        ${reactionsHtml}
        <div class="post-actions">
          <button class="post-action-btn reply-action-btn" data-post-name="${this.escapeHtml(post.metadata.name)}" data-post-author="${this.escapeHtml(author)}">Reply</button>
        </div>
      </div>
    `;
  }

  private renderReactions(post: any): string {
    if (!post.reactions || Object.keys(post.reactions).length === 0) {
      return "";
    }

    const reactionsHtml = Object.entries(post.reactions).map(([emoji, users]: [string, any]) => {
      const count = users.length;
      if (count === 0) return "";

      const state = store.getState();
      const currentUserReacted = users.includes(state.currentUser);

      return `
        <div class="reaction ${currentUserReacted ? "active" : ""}" data-post-name="${this.escapeHtml(post.metadata.name)}" data-reaction="${this.escapeHtml(emoji)}">
          <span>${this.escapeHtml(emoji)}</span>
          <span>${count}</span>
        </div>
      `;
    });

    return `<div class="reactions">${reactionsHtml.join("")}</div>`;
  }

  private formatPostContent(text: string): string {
    let html = this.escapeHtml(text);

    // Format line breaks
    html = html.replace(/\n/g, "<br>");

    // Format bold
    html = html.replace(/\*\*([^\*]+)\*\*/g, "<strong>$1</strong>");

    // Format italic
    html = html.replace(/\*([^\*]+)\*/g, "<em>$1</em>");

    // Format links
    html = html.replace(/\[([^\]]+)\]\(([^\)]+)\)/g, '<a href="$2" target="_blank">$1</a>');

    // Format reactions
    html = html.replace(/:([a-z-]+):/g, (match) => {
      const reactions: { [key: string]: string } = {
        ":smile:": "😊",
        ":frown:": "😞",
        ":like:": "👍",
        ":celebrate:": "🎉",
      };
      return reactions[match] || match;
    });

    return html;
  }

  private setupEventListeners(): void {
    const postInput = this.shadowRoot?.querySelector("#post-input") as HTMLTextAreaElement;
    const postBtn = this.shadowRoot?.querySelector("#post-btn") as HTMLButtonElement;
    const closeReplyBtn = this.shadowRoot?.querySelector("#close-reply-btn") as HTMLButtonElement;
    const boldBtn = this.shadowRoot?.querySelector("#bold-btn") as HTMLButtonElement;
    const italicBtn = this.shadowRoot?.querySelector("#italic-btn") as HTMLButtonElement;
    const linkBtn = this.shadowRoot?.querySelector("#link-btn") as HTMLButtonElement;
    const emojiBtn = this.shadowRoot?.querySelector("#emoji-btn") as HTMLButtonElement;

    if (postInput) {
      postInput.addEventListener("keydown", (e) => {
        if (e.key === "Enter" && !e.shiftKey) {
          e.preventDefault();
          this.handlePost();
        } else if (e.key === "Enter" && e.shiftKey) {
          // Allow default behavior for Shift+Enter (newline)
        }
      });
    }

    postBtn?.addEventListener("click", () => this.handlePost());
    closeReplyBtn?.addEventListener("click", () => this.closeReply());
    boldBtn?.addEventListener("click", () => this.applyFormatting("**", "**"));
    italicBtn?.addEventListener("click", () => this.applyFormatting("*", "*"));
    linkBtn?.addEventListener("click", () => this.applyLink());
    emojiBtn?.addEventListener("click", () => this.toggleEmojiPicker());

    // Reply buttons
    this.shadowRoot?.querySelectorAll(".reply-action-btn").forEach((btn) => {
      btn.addEventListener("click", (e) => {
        const postName = (e.target as HTMLElement).getAttribute("data-post-name");
        const postAuthor = (e.target as HTMLElement).getAttribute("data-post-author");
        if (postName) this.startReply(postName, postAuthor);
      });
    });

    // Reaction buttons
    this.shadowRoot?.querySelectorAll(".reaction").forEach((btn) => {
      btn.addEventListener("click", (e) => {
        const postName = (e.target as HTMLElement).closest(".reaction")?.getAttribute("data-post-name");
        const reaction = (e.target as HTMLElement).closest(".reaction")?.getAttribute("data-reaction");
        if (postName && reaction) this.toggleReaction(postName, reaction);
      });
    });
  }

  private applyFormatting(before: string, after: string): void {
    const input = this.shadowRoot?.querySelector("#post-input") as HTMLTextAreaElement;
    if (!input) return;

    const start = input.selectionStart;
    const end = input.selectionEnd;
    const text = input.value;
    const selectedText = text.substring(start, end);

    const newText = text.substring(0, start) + before + selectedText + after + text.substring(end);
    input.value = newText;
    input.selectionStart = start + before.length;
    input.selectionEnd = input.selectionStart + selectedText.length;
    input.focus();
  }

  private applyLink(): void {
    const url = prompt("Enter URL:");
    if (!url) return;
    this.applyFormatting("[", `](${url})`);
  }

  private toggleEmojiPicker(): void {
    const container = this.shadowRoot?.querySelector("#emoji-picker-container");
    if (!container) return;

    if (container.innerHTML) {
      container.innerHTML = "";
    } else {
      container.innerHTML = `
        <div class="emoji-picker">
          <button class="emoji-btn" data-emoji=":smile:">😊</button>
          <button class="emoji-btn" data-emoji=":frown:">😞</button>
          <button class="emoji-btn" data-emoji=":like:">👍</button>
          <button class="emoji-btn" data-emoji=":celebrate:">🎉</button>
        </div>
      `;

      container.querySelectorAll(".emoji-btn").forEach((btn) => {
        btn.addEventListener("click", (e) => {
          const emoji = (e.target as HTMLElement).getAttribute("data-emoji");
          if (emoji) {
            const input = this.shadowRoot?.querySelector("#post-input") as HTMLTextAreaElement;
            if (input) {
              input.value += emoji;
              input.focus();
              container.innerHTML = "";
            }
          }
        });
      });
    }
  }

  private startReply(postName: string, postAuthor: string | null): void {
    const label = this.shadowRoot?.querySelector("#reply-label") as HTMLElement;
    const closeBtn = this.shadowRoot?.querySelector("#close-reply-btn") as HTMLButtonElement;

    if (label) {
      label.style.display = "block";
      label.textContent = `Replying to ${this.escapeHtml(postAuthor || "unknown")}`;
    }
    if (closeBtn) closeBtn.style.display = "block";

    store.setState({ currentPostReplyTo: postName } as any);

    const input = this.shadowRoot?.querySelector("#post-input") as HTMLTextAreaElement;
    if (input) input.focus();
  }

  private closeReply(): void {
    const label = this.shadowRoot?.querySelector("#reply-label") as HTMLElement;
    const closeBtn = this.shadowRoot?.querySelector("#close-reply-btn") as HTMLButtonElement;

    if (label) label.style.display = "none";
    if (closeBtn) closeBtn.style.display = "none";

    store.setState({ currentPostReplyTo: null } as any);
  }

  private async handlePost(): Promise<void> {
    const input = this.shadowRoot?.querySelector("#post-input") as HTMLTextAreaElement;
    if (!input || !input.value.trim()) return;

    const state = store.getState();
    if (!state.token || !state.currentWorkspace || !state.currentChannel) return;

    try {
      const postData: any = {
        msg: input.value,
      };

      const replyTo = (state as any).currentPostReplyTo;
      if (replyTo) {
        postData.parent = replyTo;
      }

      await api.createPost(state.currentWorkspace, state.currentChannel, postData, state.token);

      input.value = "";
      this.closeReply();

      // Reload posts
      const posts = await api.listPosts(state.currentWorkspace, state.currentChannel, state.token);
      store.setState({
        posts: posts.map((post) => ({
          msg: post.data.msg,
          parent: post.data.parent,
          reactions: post.data.reactions,
          extensions: post.data.extensions,
          metadata: {
            name: post.name,
            author: post.author,
            created: post.created,
          },
        })),
      });
    } catch (error) {
      store.setState({
        error: `Failed to post: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  private async toggleReaction(postName: string, reaction: string): Promise<void> {
    const state = store.getState();
    if (!state.token || !state.currentWorkspace || !state.currentChannel) return;

    const post = state.posts.find((p) => p.metadata.name === postName);
    if (!post) return;

    const reactions = post.reactions || {};
    const reactionList = reactions[reaction] || [];
    const userIndex = reactionList.indexOf(state.currentUser || "");

    if (userIndex >= 0) {
      reactionList.splice(userIndex, 1);
    } else {
      reactionList.push(state.currentUser || "");
    }

    if (reactionList.length === 0) {
      delete reactions[reaction];
    } else {
      reactions[reaction] = reactionList;
    }

    const updatedPost = { ...post, reactions };

    try {
      await api.updatePost(state.currentWorkspace, state.currentChannel, postName, updatedPost, state.token);

      // Update post in store
      const updatedPosts = state.posts.map((p) => (p.metadata.name === postName ? updatedPost : p));
      store.setState({ posts: updatedPosts });
    } catch (error) {
      store.setState({
        error: `Failed to update reaction: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  private async subscribeToChannel(): Promise<void> {
    const state = store.getState();
    if (!state.token || !state.currentWorkspace || !state.currentChannel) return;

    try {
      this.unsubscribePost = await api.subscribeToChannel(
        state.currentWorkspace,
        state.currentChannel,
        state.token,
        (event) => {
          // Handle new post from subscription
          this.loadPostsFromChannel();
        },
        (error) => {
          // Handle subscription error
          console.error("Subscription error:", error);
        }
      );
    } catch (error) {
      console.error("Failed to subscribe:", error);
    }
  }

  private async loadPostsFromChannel(): Promise<void> {
    const state = store.getState();
    if (!state.token || !state.currentWorkspace || !state.currentChannel) return;

    try {
      const posts = await api.listPosts(state.currentWorkspace, state.currentChannel, state.token);
      store.setState({
        posts: posts.map((post) => ({
          msg: post.data.msg,
          parent: post.data.parent,
          reactions: post.data.reactions,
          extensions: post.data.extensions,
          metadata: {
            name: post.name,
            author: post.author,
            created: post.created,
          },
        })),
      });
    } catch (error) {
      // Silently handle errors
    }
  }

  private escapeHtml(text: string): string {
    const div = document.createElement("div");
    div.textContent = text;
    return div.innerHTML;
  }
}

