  color: #3498db;
  text-decoration: none;
}

a:hover {
  text-decoration: underline;
}

/* Focus styles for accessibility */
button:focus,
input:focus,
textarea:focus {
  outline: 2px solid #3498db;
  outline-offset: 2px;
}

/* Hide scrollbar for webkit browsers while keeping functionality */
::-webkit-scrollbar {
