import { store } from "../store";
import * as api from "../api";
import { LoginModal } from "./login-modal";
import { Sidebar } from "./sidebar";
import { ChatArea } from "./chat-area";

export class AppComponent extends HTMLElement {
  private loginModal: LoginModal | null = null;
  private sidebar: Sidebar | null = null;
  private chatArea: ChatArea | null = null;
  private unsubscribe: (() => void) | null = null;

  constructor() {
    super();
    this.attachShadow({ mode: "open" });
  }

  connectedCallback(): void {
    this.render();
    this.unsubscribe = store.subscribe(() => this.render());
  }

  disconnectedCallback(): void {
    if (this.unsubscribe) {
      this.unsubscribe();
    }
  }

  private render(): void {
    const state = store.getState();
    if (!this.shadowRoot) return;

    // Create main layout
    this.shadowRoot.innerHTML = `
      <style>
        :host {
          display: flex;
          height: 100vh;
          font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
          background: #ffffff;
          color: #000;
        }

        .container {
          display: flex;
          flex-direction: column;
          width: 100%;
          height: 100%;
        }

        .main-content {
          display: flex;
          flex: 1;
          overflow: hidden;
        }

        .header {
          background: #2c3e50;
          color: white;
          padding: 1rem;
          display: flex;
          justify-content: space-between;
          align-items: center;
          border-bottom: 1px solid #34495e;
        }

        .header h1 {
          margin: 0;
          font-size: 1.5rem;
        }

        .user-info {
          display: flex;
          align-items: center;
          gap: 1rem;
        }

        .username {
          color: #ecf0f1;
        }

        .logout-btn {
          background: #e74c3c;
          color: white;
          border: none;
          padding: 0.5rem 1rem;
          border-radius: 0.25rem;
          cursor: pointer;
          font-size: 0.875rem;
        }

        .logout-btn:hover {
          background: #c0392b;
        }

        .not-logged-in {
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          flex: 1;
          opacity: 0.5;
          pointer-events: none;
        }
      </style>

      <div class="container">
        ${
          state.currentUser
            ? `
          <div class="header">
            <h1>M3ssag1n8</h1>
            <div class="user-info">
              <span class="username">Logged in as: <strong>${this.escapeHtml(state.currentUser)}</strong></span>
              <button class="logout-btn">Logout</button>
            </div>
          </div>
          <div class="main-content">
            <m3-sidebar></m3-sidebar>
            <m3-chat-area></m3-chat-area>
          </div>
        `
            : `
          <div class="not-logged-in">
            <p>Please log in to continue</p>
          </div>
        `
        }
      </div>

      <m3-login-modal ${state.currentUser ? 'style="display: none;"' : ""}></m3-login-modal>
    `;

    // Setup event listeners
    const logoutBtn = this.shadowRoot.querySelector(".logout-btn");
    if (logoutBtn) {
      logoutBtn.addEventListener("click", () => this.handleLogout());
    }

    // Ensure custom elements are defined
    this.ensureComponentsRegistered();
  }

  private ensureComponentsRegistered(): void {
    if (!customElements.get("m3-login-modal")) {
      customElements.define("m3-login-modal", LoginModal);
    }
    if (!customElements.get("m3-sidebar")) {
      customElements.define("m3-sidebar", Sidebar);
    }
    if (!customElements.get("m3-chat-area")) {
      customElements.define("m3-chat-area", ChatArea);
    }
  }

  private async handleLogout(): Promise<void> {
    const state = store.getState();
    if (!state.token) return;

    try {
      await api.logout(state.token);
      store.reset();
    } catch (error) {
      store.setState({
        error: `Logout failed: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  private escapeHtml(text: string): string {
    const div = document.createElement("div");
    div.textContent = text;
    return div.innerHTML;
  }
}

customElements.define("m3-app", AppComponent);

