export async function subscribeToChannel(
  workspaceName: string,
  channelName: string,
  token: string,
  onMessage: (event: any) => void,
  onError: (error: Error) => void
): Promise<() => void> {
  let abort = false;

  const promise = fetchEventSource(
    `${API_BASE}${workspaceName}/channels/${channelName}/posts`,
    {
      method: "GET",
      headers: {
        Authorization: `Bearer ${token}`,
      },
      onmessage: (event) => {
        if (abort) return;
        try {
          const data = JSON.parse(event.data);
          onMessage(data);
        } catch (e) {
          onError(new Error("Failed to parse SSE message"));
        }
      },
      onerror: (err) => {
        if (!abort) {
          onError(new Error(`SSE connection error: ${err}`));
        }
      },
    }
  );

  return () => {
    abort = true;
  };
}

